     1→// OpenFang Hands Page — curated autonomous capability packages
     2→'use strict';
     3→
     4→function handsPage() {
     5→  return {
     6→    tab: 'available',
     7→    hands: [],
     8→    instances: [],
     9→    loading: true,
    10→    activeLoading: false,
    11→    loadError: '',
    12→    activatingId: null,
    13→    activateResult: null,
    14→    detailHand: null,
    15→    settingsValues: {},
    16→    _toastTimer: null,
    17→    browserViewer: null,
    18→    browserViewerOpen: false,
    19→    _browserPollTimer: null,
    20→
    21→    // ── Setup Wizard State ──────────────────────────────────────────────
    22→    setupWizard: null,
    23→    setupStep: 1,
    24→    setupLoading: false,
    25→    setupChecking: false,
    26→    clipboardMsg: null,
    27→    _clipboardTimer: null,
    28→    detectedPlatform: 'linux',
    29→    installPlatforms: {},
    30→
    31→    async loadData() {
    32→      this.loading = true;
    33→      this.loadError = '';
    34→      try {
    35→        var data = await OpenFangAPI.get('/api/hands');
    36→        this.hands = data.hands || [];
    37→      } catch(e) {
    38→        this.hands = [];
    39→        this.loadError = e.message || 'Could not load hands.';
    40→      }
    41→      this.loading = false;
    42→    },
    43→
    44→    async loadActive() {
    45→      this.activeLoading = true;
    46→      try {
    47→        var data = await OpenFangAPI.get('/api/hands/active');
    48→        this.instances = (data.instances || []).map(function(i) {
    49→          i._stats = null;
    50→          return i;
    51→        });
    52→      } catch(e) {
    53→        this.instances = [];
    54→      }
    55→      this.activeLoading = false;
    56→    },
    57→
    58→    getHandIcon(handId) {
    59→      for (var i = 0; i < this.hands.length; i++) {
    60→        if (this.hands[i].id === handId) return this.hands[i].icon;
    61→      }
    62→      return '\u{1F91A}';
    63→    },
    64→
    65→    async showDetail(handId) {
    66→      try {
    67→        var data = await OpenFangAPI.get('/api/hands/' + handId);
    68→        this.detailHand = data;
    69→      } catch(e) {
    70→        for (var i = 0; i < this.hands.length; i++) {
    71→          if (this.hands[i].id === handId) {
    72→            this.detailHand = this.hands[i];
    73→            break;
    74→          }
    75→        }
    76→      }
    77→    },
    78→
    79→    // ── Setup Wizard ────────────────────────────────────────────────────
    80→
    81→    async activate(handId) {
    82→      this.openSetupWizard(handId);
    83→    },
    84→
    85→    async openSetupWizard(handId) {
    86→      this.setupLoading = true;
    87→      this.setupWizard = null;
    88→      try {
    89→        var data = await OpenFangAPI.get('/api/hands/' + handId);
    90→        // Pre-populate settings defaults
    91→        this.settingsValues = {};
    92→        if (data.settings && data.settings.length > 0) {
    93→          for (var i = 0; i < data.settings.length; i++) {
    94→            var s = data.settings[i];
    95→            this.settingsValues[s.key] = s.default || '';
    96→          }
    97→        }
    98→        // Detect platform from server response, fallback to client-side
    99→        if (data.server_platform) {
   100→          this.detectedPlatform = data.server_platform;
   101→        } else {
   102→          this._detectClientPlatform();
   103→        }
   104→        // Initialize per-requirement platform selections
   105→        this.installPlatforms = {};
   106→        if (data.requirements) {
   107→          for (var j = 0; j < data.requirements.length; j++) {
   108→            this.installPlatforms[data.requirements[j].key] = this.detectedPlatform;
   109→          }
   110→        }
   111→        this.setupWizard = data;
   112→        // Skip deps step if no requirements
   113→        var hasReqs = data.requirements && data.requirements.length > 0;
   114→        this.setupStep = hasReqs ? 1 : 2;
   115→      } catch(e) {
   116→        this.showToast('Could not load hand details: ' + (e.message || 'unknown error'));
   117→      }
   118→      this.setupLoading = false;
   119→    },
   120→
   121→    _detectClientPlatform() {
   122→      var ua = (navigator.userAgent || '').toLowerCase();
   123→      if (ua.indexOf('mac') !== -1) {
   124→        this.detectedPlatform = 'macos';
   125→      } else if (ua.indexOf('win') !== -1) {
   126→        this.detectedPlatform = 'windows';
   127→      } else {
   128→        this.detectedPlatform = 'linux';
   129→      }
   130→    },
   131→
   132→    // ── Auto-Install Dependencies ───────────────────────────────────
   133→    installProgress: null,   // null = idle, object = { status, current, total, results, error }
   134→
   135→    async installDeps() {
   136→      if (!this.setupWizard) return;
   137→      var handId = this.setupWizard.id;
   138→      var missing = (this.setupWizard.requirements || []).filter(function(r) { return !r.satisfied; });
   139→      if (missing.length === 0) {
   140→        this.showToast('All dependencies already installed!');
   141→        return;
   142→      }
   143→
   144→      this.installProgress = {
   145→        status: 'installing',
   146→        current: 0,
   147→        total: missing.length,
   148→        currentLabel: missing[0] ? missing[0].label : '',
   149→        results: [],
   150→        error: null
   151→      };
   152→
   153→      try {
   154→        var data = await OpenFangAPI.post('/api/hands/' + handId + '/install-deps', {});
   155→        var results = data.results || [];
   156→        this.installProgress.results = results;
   157→        this.installProgress.current = results.length;
   158→        this.installProgress.status = 'done';
   159→
   160→        // Update requirements from server response
   161→        if (data.requirements && this.setupWizard.requirements) {
   162→          for (var i = 0; i < this.setupWizard.requirements.length; i++) {
   163→            var existing = this.setupWizard.requirements[i];
   164→            for (var j = 0; j < data.requirements.length; j++) {
   165→              if (data.requirements[j].key === existing.key) {
   166→                existing.satisfied = data.requirements[j].satisfied;
   167→                break;
   168→              }
   169→            }
   170→          }
   171→          this.setupWizard.requirements_met = data.requirements_met;
   172→        }
   173→
   174→        var installed = results.filter(function(r) { return r.status === 'installed' || r.status === 'already_installed'; }).length;
   175→        var failed = results.filter(function(r) { return r.status === 'error' || r.status === 'timeout'; }).length;
   176→
   177→        if (data.requirements_met) {
   178→          this.showToast('All dependencies installed successfully!');
   179→          // Auto-advance to step 2 after a short delay
   180→          var self = this;
   181→          setTimeout(function() {
   182→            self.installProgress = null;
   183→            self.setupNextStep();
   184→          }, 1500);
   185→        } else if (failed > 0) {
   186→          this.installProgress.error = failed + ' dependency(ies) failed to install. Check the details below.';
   187→        }
   188→      } catch(e) {
   189→        this.installProgress = {
   190→          status: 'error',
   191→          current: 0,
   192→          total: missing.length,
   193→          currentLabel: '',
   194→          results: [],
   195→          error: e.message || 'Installation request failed'
   196→        };
   197→      }
   198→    },
   199→
   200→    getInstallResultIcon(status) {
   201→      if (status === 'installed' || status === 'already_installed') return '\u2713';
   202→      if (status === 'error' || status === 'timeout') return '\u2717';
   203→      return '\u2022';
   204→    },
   205→
   206→    getInstallResultClass(status) {
   207→      if (status === 'installed' || status === 'already_installed') return 'dep-met';
   208→      if (status === 'error' || status === 'timeout') return 'dep-missing';
   209→      return '';
   210→    },
   211→
   212→    async recheckDeps() {
   213→      if (!this.setupWizard) return;
   214→      this.setupChecking = true;
   215→      try {
   216→        var data = await OpenFangAPI.post('/api/hands/' + this.setupWizard.id + '/check-deps', {});
   217→        if (data.requirements && this.setupWizard.requirements) {
   218→          for (var i = 0; i < this.setupWizard.requirements.length; i++) {
   219→            var existing = this.setupWizard.requirements[i];
   220→            for (var j = 0; j < data.requirements.length; j++) {
   221→              if (data.requirements[j].key === existing.key) {
   222→                existing.satisfied = data.requirements[j].satisfied;
   223→                break;
   224→              }
   225→            }
   226→          }
   227→          this.setupWizard.requirements_met = data.requirements_met;
   228→        }
   229→        if (data.requirements_met) {
   230→          this.showToast('All dependencies satisfied!');
   231→        }
   232→      } catch(e) {
   233→        this.showToast('Check failed: ' + (e.message || 'unknown'));
   234→      }
   235→      this.setupChecking = false;
   236→    },
   237→
   238→    getInstallCmd(req) {
   239→      if (!req || !req.install) return null;
   240→      var inst = req.install;
   241→      var plat = this.installPlatforms[req.key] || this.detectedPlatform;
   242→      if (plat === 'macos' && inst.macos) return inst.macos;
   243→      if (plat === 'windows' && inst.windows) return inst.windows;
   244→      if (plat === 'linux') {
   245→        return inst.linux_apt || inst.linux_dnf || inst.linux_pacman || inst.pip || null;
   246→      }
   247→      return inst.pip || inst.macos || inst.windows || inst.linux_apt || null;
   248→    },
   249→
   250→    getLinuxVariant(req) {
   251→      if (!req || !req.install) return null;
   252→      var inst = req.install;
   253→      var plat = this.installPlatforms[req.key] || this.detectedPlatform;
   254→      if (plat !== 'linux') return null;
   255→      // Return all available Linux variants
   256→      var variants = [];
   257→      if (inst.linux_apt) variants.push({ label: 'apt', cmd: inst.linux_apt });
   258→      if (inst.linux_dnf) variants.push({ label: 'dnf', cmd: inst.linux_dnf });
   259→      if (inst.linux_pacman) variants.push({ label: 'pacman', cmd: inst.linux_pacman });
   260→      if (inst.pip) variants.push({ label: 'pip', cmd: inst.pip });
   261→      return variants.length > 1 ? variants : null;
   262→    },
   263→
   264→    copyToClipboard(text) {
   265→      var self = this;
   266→      navigator.clipboard.writeText(text).then(function() {
   267→        self.clipboardMsg = text;
   268→        if (self._clipboardTimer) clearTimeout(self._clipboardTimer);
   269→        self._clipboardTimer = setTimeout(function() { self.clipboardMsg = null; }, 2000);
   270→      });
   271→    },
   272→
   273→    get setupReqsMet() {
   274→      if (!this.setupWizard || !this.setupWizard.requirements) return 0;
   275→      var count = 0;
   276→      for (var i = 0; i < this.setupWizard.requirements.length; i++) {
   277→        if (this.setupWizard.requirements[i].satisfied) count++;
   278→      }
   279→      return count;
   280→    },
   281→
   282→    get setupReqsTotal() {
   283→      if (!this.setupWizard || !this.setupWizard.requirements) return 0;
   284→      return this.setupWizard.requirements.length;
   285→    },
   286→
   287→    get setupAllReqsMet() {
   288→      return this.setupReqsTotal > 0 && this.setupReqsMet === this.setupReqsTotal;
   289→    },
   290→
   291→    get setupHasReqs() {
   292→      return this.setupReqsTotal > 0;
   293→    },
   294→
   295→    get setupHasSettings() {
   296→      return this.setupWizard && this.setupWizard.settings && this.setupWizard.settings.length > 0;
   297→    },
   298→
   299→    setupNextStep() {
   300→      if (this.setupStep === 1 && this.setupHasSettings) {
   301→        this.setupStep = 2;
   302→      } else if (this.setupStep === 1) {
   303→        this.setupStep = 3;
   304→      } else if (this.setupStep === 2) {
   305→        this.setupStep = 3;
   306→      }
   307→    },
   308→
   309→    setupPrevStep() {
   310→      if (this.setupStep === 3 && this.setupHasSettings) {
   311→        this.setupStep = 2;
   312→      } else if (this.setupStep === 3) {
   313→        this.setupStep = this.setupHasReqs ? 1 : 2;
   314→      } else if (this.setupStep === 2 && this.setupHasReqs) {
   315→        this.setupStep = 1;
   316→      }
   317→    },
   318→
   319→    closeSetupWizard() {
   320→      this.setupWizard = null;
   321→      this.setupStep = 1;
   322→      this.setupLoading = false;
   323→      this.setupChecking = false;
   324→      this.clipboardMsg = null;
   325→      this.installPlatforms = {};
   326→    },
   327→
   328→    async launchHand() {
   329→      if (!this.setupWizard) return;
   330→      var handId = this.setupWizard.id;
   331→      var config = {};
   332→      for (var key in this.settingsValues) {
   333→        config[key] = this.settingsValues[key];
   334→      }
   335→      this.activatingId = handId;
   336→      try {
   337→        var data = await OpenFangAPI.post('/api/hands/' + handId + '/activate', { config: config });
   338→        this.showToast('Hand "' + handId + '" activated as ' + (data.agent_name || data.instance_id));
   339→        this.closeSetupWizard();
   340→        await this.loadActive();
   341→        this.tab = 'active';
   342→      } catch(e) {
   343→        this.showToast('Activation failed: ' + (e.message || 'unknown error'));
   344→      }
   345→      this.activatingId = null;
   346→    },
   347→
   348→    selectOption(settingKey, value) {
   349→      this.settingsValues[settingKey] = value;
   350→    },
   351→
   352→    getSettingDisplayValue(setting) {
   353→      var val = this.settingsValues[setting.key] || setting.default || '';
   354→      if (setting.setting_type === 'toggle') {
   355→        return val === 'true' ? 'Enabled' : 'Disabled';
   356→      }
   357→      if (setting.setting_type === 'select' && setting.options) {
   358→        for (var i = 0; i < setting.options.length; i++) {
   359→          if (setting.options[i].value === val) return setting.options[i].label;
   360→        }
   361→      }
   362→      return val || '-';
   363→    },
   364→
   365→    // ── Existing methods ────────────────────────────────────────────────
   366→
   367→    async pauseHand(inst) {
   368→      try {
   369→        await OpenFangAPI.post('/api/hands/instances/' + inst.instance_id + '/pause', {});
   370→        inst.status = 'Paused';
   371→      } catch(e) {
   372→        this.showToast('Pause failed: ' + (e.message || 'unknown error'));
   373→      }
   374→    },
   375→
   376→    async resumeHand(inst) {
   377→      try {
   378→        await OpenFangAPI.post('/api/hands/instances/' + inst.instance_id + '/resume', {});
   379→        inst.status = 'Active';
   380→      } catch(e) {
   381→        this.showToast('Resume failed: ' + (e.message || 'unknown error'));
   382→      }
   383→    },
   384→
   385→    async deactivate(inst) {
   386→      var self = this;
   387→      var handName = inst.agent_name || inst.hand_id;
   388→      OpenFangToast.confirm('Deactivate Hand', 'Deactivate hand "' + handName + '"? This will kill its agent.', async function() {
   389→        try {
   390→          await OpenFangAPI.delete('/api/hands/instances/' + inst.instance_id);
   391→          self.instances = self.instances.filter(function(i) { return i.instance_id !== inst.instance_id; });
   392→          OpenFangToast.success('Hand deactivated.');
   393→        } catch(e) {
   394→          OpenFangToast.error('Deactivation failed: ' + (e.message || 'unknown error'));
   395→        }
   396→      });
   397→    },
   398→
   399→    async loadStats(inst) {
   400→      try {
   401→        var data = await OpenFangAPI.get('/api/hands/instances/' + inst.instance_id + '/stats');
   402→        inst._stats = data.metrics || {};
   403→      } catch(e) {
   404→        inst._stats = { 'Error': { value: e.message || 'Could not load stats', format: 'text' } };
   405→      }
   406→    },
   407→
   408→    formatMetric(m) {
   409→      if (!m || m.value === null || m.value === undefined) return '-';
   410→      if (m.format === 'duration') {
   411→        var secs = parseInt(m.value, 10);
   412→        if (isNaN(secs)) return String(m.value);
   413→        var h = Math.floor(secs / 3600);
   414→        var min = Math.floor((secs % 3600) / 60);
   415→        var s = secs % 60;
   416→        if (h > 0) return h + 'h ' + min + 'm';
   417→        if (min > 0) return min + 'm ' + s + 's';
   418→        return s + 's';
   419→      }
   420→      if (m.format === 'number') {
   421→        var n = parseFloat(m.value);
   422→        if (isNaN(n)) return String(m.value);
   423→        return n.toLocaleString();
   424→      }
   425→      return String(m.value);
   426→    },
   427→
   428→    showToast(msg) {
   429→      var self = this;
   430→      this.activateResult = msg;
   431→      if (this._toastTimer) clearTimeout(this._toastTimer);
   432→      this._toastTimer = setTimeout(function() { self.activateResult = null; }, 4000);
   433→    },
   434→
   435→    // ── Browser Viewer ───────────────────────────────────────────────────
   436→
   437→    isBrowserHand(inst) {
   438→      return inst.hand_id === 'browser';
   439→    },
   440→
   441→    async openBrowserViewer(inst) {
   442→      this.browserViewer = {
   443→        instance_id: inst.instance_id,
   444→        hand_id: inst.hand_id,
   445→        agent_name: inst.agent_name,
   446→        url: '',
   447→        title: '',
   448→        screenshot: '',
   449→        content: '',
   450→        loading: true,
   451→        error: ''
   452→      };
   453→      this.browserViewerOpen = true;
   454→      await this.refreshBrowserView();
   455→      this.startBrowserPolling();
   456→    },
   457→
   458→    async refreshBrowserView() {
   459→      if (!this.browserViewer) return;
   460→      var id = this.browserViewer.instance_id;
   461→      try {
   462→        var data = await OpenFangAPI.get('/api/hands/instances/' + id + '/browser');
   463→        if (data.active) {
   464→          this.browserViewer.url = data.url || '';
   465→          this.browserViewer.title = data.title || '';
   466→          this.browserViewer.screenshot = data.screenshot_base64 || '';
   467→          this.browserViewer.content = data.content || '';
   468→          this.browserViewer.error = '';
   469→        } else {
   470→          this.browserViewer.error = 'No active browser session';
   471→          this.browserViewer.screenshot = '';
   472→        }
   473→      } catch(e) {
   474→        this.browserViewer.error = e.message || 'Could not load browser state';
   475→      }
   476→      this.browserViewer.loading = false;
   477→    },
   478→
   479→    startBrowserPolling() {
   480→      var self = this;
   481→      this.stopBrowserPolling();
   482→      this._browserPollTimer = setInterval(function() {
   483→        if (self.browserViewerOpen) {
   484→          self.refreshBrowserView();
   485→        } else {
   486→          self.stopBrowserPolling();
   487→        }
   488→      }, 3000);
   489→    },
   490→
   491→    stopBrowserPolling() {
   492→      if (this._browserPollTimer) {
   493→        clearInterval(this._browserPollTimer);
   494→        this._browserPollTimer = null;
   495→      }
   496→    },
   497→
   498→    closeBrowserViewer() {
   499→      this.stopBrowserPolling();
   500→      this.browserViewerOpen = false;
   501→      this.browserViewer = null;
   502→    }
   503→  };
   504→}
